const body = $json.body || {};
const attrs = body.object_attributes || {};
const headers = $json.headers || {};

const token = headers['x-gitlab-token'] || headers['X-Gitlab-Token'];
const expectedToken = $json.expected_gitlab_webhook_token || '<SET_FROM_CREDENTIAL_OR_ENV>';

const action = attrs.action;
const isMergeRequest = body.object_kind === 'merge_request';
const isTokenValid = expectedToken !== '<SET_FROM_CREDENTIAL_OR_ENV>' && token === expectedToken;
const isOpened = attrs.state === 'opened';
const isReviewAction = ['open', 'reopen', 'update'].includes(action);
const isCodeUpdate = action !== 'update' || Boolean(attrs.oldrev);

return [{
  json: {
    ...$json,
    event_gate: {
      should_review: isMergeRequest && isTokenValid && isOpened && isReviewAction && isCodeUpdate,
      reason: {
        isMergeRequest,
        isTokenValid,
        isOpened,
        action,
        isReviewAction,
        oldrev: attrs.oldrev || null,
        isCodeUpdate,
      },
    },
  },
}];

const changes = $json.changes || [];
const processedChanges = [];
const skippedFiles = [];

const skipExtensions = ['.jpg', '.jpeg', '.png', '.gif', '.svg', '.ico', '.webp', '.bmp', '.mp3', '.wav', '.ogg', '.flac', '.mp4', '.webm', '.avi', '.mov', '.pdf', '.doc', '.docx', '.xls', '.xlsx', '.ppt', '.pptx', '.zip', '.rar', '.tar', '.gz', '.7z', '.bin', '.exe', '.dll', '.so', '.dylib', '.ttf', '.otf', '.woff', '.woff2'];
const skipDirs = ['node_modules/', 'dist/', 'build/', '.gradle/', '.next/', 'coverage/'];
const lockFiles = ['package-lock.json', 'pnpm-lock.yaml', 'yarn.lock', 'gradle.lockfile', 'poetry.lock'];

function shouldSkipPath(path = '') {
  const lower = path.toLowerCase();
  return skipExtensions.some(ext => lower.endsWith(ext)) || skipDirs.some(dir => lower.includes(dir));
}
function isLockFile(path = '') { return lockFiles.some(name => path.endsWith(name)); }
function isBinaryDiff(diff = '') { return diff.includes('Binary files') || diff.includes('\0'); }
function getChangeType(change) {
  if (change.deleted_file) return 'delete';
  if (change.renamed_file && !change.diff) return 'rename';
  if (change.renamed_file) return 'rename+modify';
  if (change.new_file) return 'add';
  return 'modify';
}
function trimDiff(diff = '', limit = 2000) {
  if (diff.length <= limit) return diff;
  const half = Math.floor(limit / 2);
  return `${diff.slice(0, half)}\n... diff truncated ...\n${diff.slice(-half)}`;
}

let totalChars = 0;
const totalLimit = 9000;
const fileLimit = 8;

for (const change of changes) {
  const path = change.new_path || change.old_path || '';
  const type = getChangeType(change);
  const diff = change.diff || '';

  if (processedChanges.length >= fileLimit) {
    skippedFiles.push({ path, reason: 'review file budget exceeded' });
    continue;
  }
  if (['delete', 'rename'].includes(type)) {
    skippedFiles.push({ path, reason: type });
    continue;
  }
  if (shouldSkipPath(path) || isBinaryDiff(diff)) {
    skippedFiles.push({ path, reason: 'binary/generated/media' });
    continue;
  }
  if (isLockFile(path)) {
    processedChanges.push({ file_path: path, old_path: change.old_path !== change.new_path ? change.old_path : null, change_type: type, diff: '[lockfile changed: diff omitted; check dependency/security impact if relevant]', is_summarized: true });
    continue;
  }
  if (totalChars >= totalLimit) {
    skippedFiles.push({ path, reason: 'total diff budget exceeded' });
    continue;
  }

  const trimmed = trimDiff(diff);
  totalChars += trimmed.length;
  processedChanges.push({ file_path: path, old_path: change.old_path !== change.new_path ? change.old_path : null, change_type: type, diff: trimmed, is_summarized: diff.length !== trimmed.length });
}

return [{
  json: {
    project_id: $json.project_id,
    mr_iid: $json.iid,
    title: $json.title,
    description: $json.description || '',
    source_branch: $json.source_branch,
    target_branch: $json.target_branch,
    changed_file_count: changes.length,
    reviewed_file_count: processedChanges.length,
    skipped_file_count: skippedFiles.length,
    skipped_files: skippedFiles,
    files: processedChanges,
  },
}];

return [{
  json: {
    ...$json,
    llm_body: {
      model: 'gpt-4o-mini',
      temperature: 0.2,
      max_tokens: 1800,
      messages: [
        {
          role: 'developer',
          content: 'You are a thoughtful senior engineer writing a natural Korean GitLab MR review comment. Be concrete, collaborative, and grounded in the diff. Avoid generic checklists and robotic report formatting.',
        },
        {
          role: 'user',
          content: $json.review_prompt,
        },
      ],
    },
  },
}];

const aiText = $json.choices?.[0]?.message?.content || '리뷰 결과를 생성하지 못했습니다.';
const context = $('Build Review Summary').item.json;

return [{
  json: {
    project_id: context.project_id,
    mr_iid: context.mr_iid,
    body: aiText,
  },
}];
